import"./hoisted.CvN_TNCx.js";document.addEventListener("astro:page-load",()=>{const e=document.getElementById("curhat-form"),t=document.getElementById("feedback-modal"),i=document.getElementById("feedback-message"),r=t?.querySelector(".modal-close-btn"),a=e?.querySelector(".submit-button");if(e instanceof HTMLFormElement&&t instanceof HTMLElement&&i instanceof HTMLParagraphElement&&r instanceof HTMLButtonElement&&a instanceof HTMLButtonElement){const n=s=>{i.textContent=s,t.classList.add("is-visible")};e.addEventListener("submit",async s=>{s.preventDefault(),a.disabled=!0;const c=new FormData(e);try{const o=await fetch("/api/curhat",{method:"POST",body:c}),m=await o.json();o.ok?(n("Terima kasih telah berbagi cerita. Tetap semangat, ya!"),e.reset()):n(`Gagal mengirim curhat: ${m.message||"Terjadi kesalahan"}`)}catch{n("Gagal mengirim curhat. Periksa koneksi internet Anda.")}finally{a.disabled=!1}}),r.addEventListener("click",()=>{t.classList.remove("is-visible")})}});
